import {
  Body,
  Controller,
  Delete,
  Get,
  Param,
  Patch,
  Post,
  Query,
  UseGuards,
  UseInterceptors,
} from '@nestjs/common';
import { SlotService } from './slot.service';
import { RmAdminAuthGuard } from '../../sso/gaurds/rm-admin-auth.gaurd';
import { RolesGuard } from '../../sso/gaurds/roles.gaurd';
import { Roles } from '../../sso/decorators/roles.decorator';
import { RolesEnum } from 'src/enums/roles.enum';
import {
  ListSlotsDto,
  MoveVoucherToSlotDto,
  SlotDropdownDto,
  UpdateSlotStatusDto,
} from './dto/list-slot.dto';
import { AddBatchSlotsDto, UpdateBatchSlotDto } from './dto/add-slot.dto';
import { User } from 'src/modules/sso/decorators/user.decorator';
import { UserActivityInterceptor } from 'src/interceptors/user_activity.interceptor';
import { UserActionsEnum } from 'src/enums/event-messages.enum';
import { AllocationService } from './allocation.service';
import { CommonFindAllQueryDto } from 'src/helpers/dto/commonFindAll.dto';

@Controller('batch-slots')
export class SlotController {
  constructor(
    private readonly slotService: SlotService,
    private readonly allocationService: AllocationService,
  ) {}

  @UseGuards(RmAdminAuthGuard, RolesGuard)
  @Roles(
    RolesEnum.ADMIN,
    RolesEnum.SUPER_ADMIN,
    RolesEnum.MIS,
    RolesEnum.BIS,
    RolesEnum.SALES_RSH,
    RolesEnum.CRM,
  )
  @Get('list')
  async listBatches(@Query() queryDto: ListSlotsDto): Promise<any> {
    return this.slotService.listSlots(queryDto);
  }

  @UseGuards(RmAdminAuthGuard, RolesGuard)
  @Roles(RolesEnum.ADMIN, RolesEnum.SUPER_ADMIN)
  @UseInterceptors(
    UserActivityInterceptor(UserActionsEnum.CREATED, 'eoi_batch_slots'),
  )
  @Post('add')
  async addSlot(
    @User() user: any,
    @Body() dto: AddBatchSlotsDto,
  ): Promise<any> {
    return this.slotService.addSlots(user, dto);
  }

  @UseGuards(RmAdminAuthGuard, RolesGuard)
  @Roles(RolesEnum.ADMIN, RolesEnum.SUPER_ADMIN)
  @UseInterceptors(
    UserActivityInterceptor(UserActionsEnum.UPDATED, 'eoi_batch_slots'),
  )
  @Patch('update/:slotId')
  async updateSlotEndTime(
    @Param('slotId') slotId: string,
    @Body() dto: UpdateBatchSlotDto,
  ): Promise<any> {
    return this.slotService.updateSlot(slotId, dto);
  }

  @UseGuards(RmAdminAuthGuard, RolesGuard)
  @Roles(RolesEnum.ADMIN, RolesEnum.SUPER_ADMIN)
  @UseInterceptors(
    UserActivityInterceptor(UserActionsEnum.DELETED, 'eoi_batch_slots'),
  )
  @Delete('delete/:slotId')
  async deleteBatch(
    @User() user: any,
    @Param('slotId') slotId: string,
  ): Promise<any> {
    return await this.slotService.deleteSlot(user, slotId);
  }

  @UseGuards(RmAdminAuthGuard, RolesGuard)
  @Roles(RolesEnum.ADMIN, RolesEnum.SUPER_ADMIN)
  @Get('dropdown/:batchId')
  async getSlotDropdown(
    @Param('batchId') batchId: string,
    @Query() queryDto: SlotDropdownDto,
  ) {
    return this.slotService.getSlotDropdown(batchId, queryDto);
  }

  @UseGuards(RmAdminAuthGuard, RolesGuard)
  @Roles(RolesEnum.ADMIN, RolesEnum.SUPER_ADMIN)
  @UseInterceptors(
    UserActivityInterceptor(UserActionsEnum.UPDATED, 'eoi_batch_slots'),
  )
  @Patch('update-status/:slotId')
  async updateSlotStatus(
    @Param('slotId') slotId: string,

    @Body() body: UpdateSlotStatusDto,
    @User() user: any,
  ) {
    return this.slotService.updateSlotStatus(slotId, body, user);
  }

  @UseGuards(RmAdminAuthGuard, RolesGuard)
  @Roles(
    RolesEnum.ADMIN,
    RolesEnum.SUPER_ADMIN,
    RolesEnum.MIS,
    RolesEnum.BIS,
    RolesEnum.SALES_RSH,
    RolesEnum.CRM,
  )
  @Get('statistics/:batchId')
  async getSlotStatistics(@Param('batchId') batchId: string): Promise<any> {
    return this.slotService.getSlotStatistics(batchId);
  }

  @UseGuards(RmAdminAuthGuard, RolesGuard)
  @Roles(RolesEnum.ADMIN, RolesEnum.SUPER_ADMIN)
  @UseInterceptors(
    UserActivityInterceptor(UserActionsEnum.UPDATED, 'eoi_batch_vouchers'),
  )
  @Patch('move-user/:MappedvoucherId')
  async moveVoucherToAnotherSlot(
    @Param('MappedvoucherId') MappedvoucherId: string,
    @Body() dto: MoveVoucherToSlotDto,
    @User() user: any,
  ) {
    return this.allocationService.moveVoucherToAnotherSlot(
      MappedvoucherId,
      dto,
      user,
    );
  }
  @UseGuards(RmAdminAuthGuard, RolesGuard)
  @Roles(
    RolesEnum.ADMIN,
    RolesEnum.SUPER_ADMIN,
    RolesEnum.MIS,
    RolesEnum.BIS,
    RolesEnum.SALES_RSH,
    RolesEnum.CRM,
  )
  @Get('vouchers/:slotId')
  async getBatchVouchers(
    @Param('slotId') slotId: string,
    @Query() query: CommonFindAllQueryDto,
  ) {
    return await this.allocationService.getBatchVouchers(slotId, query);
  }
  @UseGuards(RmAdminAuthGuard, RolesGuard)
  @Roles(
    RolesEnum.ADMIN,
    RolesEnum.SUPER_ADMIN,
    RolesEnum.MIS,
    RolesEnum.BIS,
    RolesEnum.SALES_RSH,
    RolesEnum.CRM,
  )
  @Get('export')
  async exportSlotsExcel(@Query() queryDto: ListSlotsDto) {
    return this.slotService.exportSlotsExcel(queryDto);
  }
}

import {
  Column,
  CreateDateColumn,
  Entity,
  Index,
  JoinColumn,
  ManyToOne,
  PrimaryGeneratedColumn,
} from 'typeorm';

import { EoiBatch } from './batch.entity';
import { EoiBatchSlot } from './slot.entity';
import { BatchStage, BatchVoucherStatus } from 'src/enums/batch-manager.enums';
import { VoucherForm } from 'src/entities';

/**
 * Maps a voucher to a specific slot inside a batch.
 * Snapshot fields preserve applicant data
 * at mapping time.
 */
@Entity('eoi_batch_vouchers')
@Index(['voucherId', 'stage'], {
  unique: true,
})
export class EoiBatchVoucher {
  @PrimaryGeneratedColumn('uuid')
  id: string;

  @Column({
    name: 'batch_id',
    type: 'varchar',
  })
  batchId: string;

  @ManyToOne(() => EoiBatch, {
    onDelete: 'CASCADE',
  })
  @JoinColumn({ name: 'batch_id' })
  batch: EoiBatch;

  @Column({
    name: 'slot_id',
    type: 'varchar',
  })
  slotId: string;

  @ManyToOne(() => EoiBatchSlot, (slot) => slot.batchVouchers)
  @JoinColumn({ name: 'slot_id' })
  slot: EoiBatchSlot;

  @Column({
    name: 'voucher_id',
    type: 'int',
  })
  voucherId: number;

  @ManyToOne(() => VoucherForm)
  @JoinColumn({ name: 'voucher_id' })
  voucher: VoucherForm;

  /**
   * Business uniqueness scope.
   * Same voucher can participate
   * in different stages.
   */
  @Column({
    type: 'enum',
    enum: BatchStage,
  })
  stage: BatchStage;

  /**
   * Snapshot fields
   */

  @Column({
    name: 'customer_name',
    type: 'varchar',
    length: 255,
    nullable: true,
  })
  customerName?: string;

  @Column({
    name: 'email',
    type: 'varchar',
    length: 255,
    nullable: true,
  })
  email?: string;

  @Column({
    name: 'phone',
    type: 'varchar',
    length: 20,
    nullable: true,
  })
  phone?: string;

  @CreateDateColumn({
    name: 'assigned_at',
  })
  assignedAt: Date;

  @Column({
    type: 'enum',
    enum: BatchVoucherStatus,
    default: BatchVoucherStatus.INVITED,
  })
  status: BatchVoucherStatus;

  @Column({ type: 'text', nullable: true, name: 'comments' })
  comments: string;
}

import { Module } from '@nestjs/common';
import { TypeOrmModule } from '@nestjs/typeorm';
import { EoiBatch } from './entities/batch.entity';
import { EoiBatchSlot } from './entities/slot.entity';
import { EoiBatchVoucher } from './entities/batch_voucher.entity';
import { BatchService } from './batch.service';
import { SlotService } from './slot.service';
import { AllocationService } from './allocation.service';
import { BatchController } from './batch.controller';
import { SlotController } from './slot.controller';
import { VoucherForm } from 'src/modules/eoi_manager/voucher_forms/entities/voucher_form.entity';
import { InventoryType } from 'src/entities';
import { AwsService } from 'src/modules/aws/aws.service';

@Module({
  imports: [
    TypeOrmModule.forFeature([
      EoiBatch,
      EoiBatchSlot,
      EoiBatchVoucher,
      VoucherForm,
      InventoryType,
    ]),
  ],
  providers: [BatchService, SlotService, AllocationService, AwsService],
  controllers: [BatchController, SlotController],
  exports: [BatchService, SlotService, AllocationService],
})
export class BatchManagerModule {}

import {
  BadRequestException,
  Injectable,
  NotFoundException,
} from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { EntityManager, FindOptionsWhere, In, Not, Repository } from 'typeorm';
import { EoiBatchSlot } from './entities/slot.entity';
import { EoiBatch } from './entities/batch.entity';
import { logsAndErrorHandling } from 'src/utils/errorLogHandler';
import { logger } from 'src/logger/logger';
import {
  ListSlotsDto,
  SlotDropdownDto,
  UpdateSlotStatusDto,
} from './dto/list-slot.dto';
import {
  DISPLAY_DATE_TIME_FORMAT_FOR_FILE_NAME,
  SUCCESS,
} from 'src/config/constants';
import { minutesToTime, timeToMinutes } from 'src/helpers/date.helper';
import { AddBatchSlotsDto, UpdateBatchSlotDto } from './dto/add-slot.dto';
import { EoiBatchVoucher } from 'src/entities';
import {
  BatchVoucherStatus,
  SlotStatusEnum,
} from 'src/enums/batch-manager.enums';
import { PassThrough } from 'stream';
import * as ExcelJS from 'exceljs';
import { AwsService } from 'src/modules/aws/aws.service';
import { buildSlotExcelSheet } from 'src/helpers/batchSlotExport.helper';
import * as moment from 'moment';

@Injectable()
export class SlotService {
  constructor(
    @InjectRepository(EoiBatchSlot)
    private readonly slotRepo: Repository<EoiBatchSlot>,
    @InjectRepository(EoiBatch)
    private readonly batchRepo: Repository<EoiBatch>,
    @InjectRepository(EoiBatchVoucher)
    private readonly batchVoucherRepo: Repository<EoiBatchVoucher>,
    private readonly awsService: AwsService,
  ) {}

  /** Fetch slots with below filters:
   * - batchId (optional): filter slots for a specific batch
   * - date (optional): filter slots for a specific date
   * pagination and sorting by createdAt, startTime or endTime
   */
  async listSlots(queryDto: ListSlotsDto, user?: any): Promise<any> {
    logger.info('Fetching slot listing', user?.name);

    try {
      const {
        page = 1,
        limit = 10,
        batchId,
        startDate,
        endDate,
        sortBy,
        search,
      } = queryDto;

      // Validate date range pair
      if ((startDate && !endDate) || (!startDate && endDate)) {
        throw new BadRequestException(
          'Both startDate and endDate are required together',
        );
      }

      const batch = await this.batchRepo.findOne({
        where: { id: batchId },
        relations: ['campaign'],
        select: {
          id: true,
          name: true,
          isUserMapped: true,
          campaign: {
            campaignName: true,
          },
        },
      });

      const offset = (page - 1) * limit;

      const allowedSortFields = {
        createdAt: 'slot.createdAt',
        startTime: 'slot.startTime',
        endTime: 'slot.endTime',
        sequence: 'slot.sequence',
        date: 'slot.date',
      };

      let orderByField = 'slot.sequence';
      let orderDirection: 'ASC' | 'DESC' = 'ASC';

      if (sortBy) {
        const [field, direction] = sortBy.split(':');

        if (allowedSortFields[field]) {
          orderByField = allowedSortFields[field];
        }

        if (direction && ['ASC', 'DESC'].includes(direction.toUpperCase())) {
          orderDirection = direction.toUpperCase() as 'ASC' | 'DESC';
        }
      }

      const query = this.slotRepo
        .createQueryBuilder('slot')
        .select([
          'slot.id',
          'slot.name',
          'slot.batchId',
          'slot.capacity',
          'slot.sequence',
          'slot.startTime',
          'slot.endTime',
          'slot.date',
          'slot.status',
          'slot.createdAt',
        ]);

      // Batch filter
      if (batchId) {
        query.andWhere('slot.batchId = :batchId', {
          batchId,
        });
      }

      // Date range filter
      if (startDate && endDate) {
        query.andWhere('slot.date BETWEEN :startDate AND :endDate', {
          startDate,
          endDate,
        });
      }
      if (search) {
        query.andWhere('slot.name LIKE :search', { search: `%${search}%` });
      }

      query.orderBy(orderByField, orderDirection).offset(offset).limit(limit);

      const [slots, total] = await query.getManyAndCount();

      const result = slots.map((slot) => ({
        id: slot.id,
        name: slot.name,
        batchId: slot.batchId,
        capacity: slot.capacity,
        sequence: slot.sequence,
        startTime: slot.startTime,
        endTime: slot.endTime,
        date: slot.date,
        status: slot.status,
        attended: 0,
        headCount: 0,
      }));

      return {
        statusCode: SUCCESS,
        message: 'Slots fetched successfully.',
        data: {
          result,
          campaignName: batch.campaign.campaignName,
          batchName: batch.name,
          isUserMapped: batch.isUserMapped,
          total,
          page,
          limit,
        },
      };
    } catch (e) {
      logger.error('Error occurred while fetching slots', e);

      return logsAndErrorHandling('SlotService - listSlots', e, {
        queryDto,
      });
    }
  }

  /** Add slots with below rules:
   * - Slots can only be added to existing batch day and at the end of existing slots for that day
   * - Slot timings are calculated based on last slot end time and provided duration
   * - Batch day end time is not exceeded after adding new slots
   * - Number of slots added are based on provided numberOfSlots and slotDuration
   * - Slots cannot be added if users are already mapped to the batch
   */
  async addSlots(user: any, dto: AddBatchSlotsDto): Promise<any> {
    return await this.batchRepo.manager.transaction(
      async (manager: EntityManager) => {
        const { batchId } = dto;
        logger.info(`${user?.name} adding slot for ${batchId}`);

        const batch = await manager.findOne(EoiBatch, {
          where: { id: batchId },
          relations: ['days'],
        });

      const { status } = body;

      const slot = await this.slotRepo.findOne({
        where: {
          id: slotId,
        },
        select: {
          id: true,
          status: true,
        },
      });

      if (!slot) {
        throw new NotFoundException('Slot not found');
      }

      // Prevent unnecessary update
      if (slot.status === status) {
        throw new BadRequestException(`Slot is already in ${status} status`);
      }

      await this.slotRepo.update({ id: slotId }, { status });
      return {
        statusCode: SUCCESS,
        data: {
          id: slotId,
          status,
        },
        message: 'Slot status updated successfully.',
      };
    } catch (e) {
      logger.error('Error occurred while updating slot status', e);

      return logsAndErrorHandling('SlotService - updateSlotStatus', e, {
        slotId,
        body,
      });
    }
  }

  async getSlotStatistics(batchId: string): Promise<any> {
    try {
      logger.info(`Fetching slot statistics for batchId: ${batchId}`);
      // Total mapped users across all slots
      const totalEoiRecords =
        (await this.slotRepo.sum('filledCount', {
          batchId,
        })) || 0;

      // Total mapped users in processed slots - (Active, Completed, Elapsed)
      const proratedWalkin =
        (await this.slotRepo.sum('filledCount', {
          batchId,
          status: In([
            SlotStatusEnum.ACTIVE,
            SlotStatusEnum.COMPLETED,
            SlotStatusEnum.ELAPSED,
          ]),
        })) || 0;

      const attended = await this.batchVoucherRepo.count({
        where: {
          batchId,
          status: BatchVoucherStatus.ATTENDED,
        },
      });

      const data = {
        expectedWalkin: totalEoiRecords,
        proratedWalkin,
        attended,
      };

      return {
        statusCode: SUCCESS,
        message: 'Slot statistics fetched successfully.',
        data,
      };
    } catch (e) {
      logger.error('Error occurred while fetching slot statistics', e);
      return logsAndErrorHandling('SlotService - getSlotStatistics', e);
    }
  }

  async exportSlotsExcel(queryDto: ListSlotsDto): Promise<any> {
    try {
      logger.info('Exporting slots excel');
      const slotListResult = await this.listSlots(queryDto);
      const slotList = slotListResult?.data?.result ?? [];
      if (!slotList || slotList.length === 0) {
        return {
          message: 'No slots found to export.',
          data: [],
        };
      }

      const workbook = new ExcelJS.Workbook();
      buildSlotExcelSheet(workbook, { slotList });
      const buffer = await workbook.xlsx.writeBuffer();

      const timeStamp = moment().format(DISPLAY_DATE_TIME_FORMAT_FOR_FILE_NAME);
      const s3Key = `exports/slots/slots-${timeStamp}.xlsx`;

      const stream = new PassThrough();
      stream.end(buffer);

      await this.awsService.uploadToS3(s3Key, stream, true);
      return {
        message: 'Slots exported successfully.',
        data: { filePath: s3Key },
      };
    } catch (e) {
      logger.error('Error occurred while exporting slots', e);
      return logsAndErrorHandling('SlotService - exportSlotsExcel', e, {
        queryDto,
      });
    }
  }
}

 * Fetches the paginated list of batches based on search/filters
 */
async listBatches(queryDto: ListBatchesDto, user?: any): Promise<any> {
  logger.info('Fetching list of batches', user?.name);

  try {
    //update expired active batches to archived
    await this.updateExpiredBatchStatus();
    const { page, limit, sortBy } = queryDto;
    const skip = (page - 1) * limit;

    // Base query for filters (used in both queries)
    const baseQuery = this.batchRepo
      .createQueryBuilder('batch')
      .leftJoin('batch.campaign', 'campaign')
      .leftJoin('batch.slots', 'slots')
      .leftJoin('batch.batchVouchers', 'batchVouchers');

    this.applyBatchFilters(baseQuery, queryDto);
    // Sorting
    if (sortBy) {
      const [field, direction] = sortBy.split(':');
      baseQuery.orderBy(
        `batch.${field}`,
        (direction || 'DESC').toUpperCase() as 'ASC' | 'DESC',
      );
    } else {
      baseQuery.orderBy('batch.createdAt', 'DESC');
    }

    // Data query (with aggregation)
    const dataQuery = baseQuery.clone();

    dataQuery
      .select([
        'batch.id AS batch_id',
        'batch.name AS batch_name',
        'batch.stage AS batch_stage',
        'batch.startDate AS batch_startDate',
        'batch.endDate AS batch_endDate',
        'batch.capacityPerSlot AS capacity_per_slot',
        'batch.slotDuration AS batch_slotDuration',
        'batch.createdAt AS batch_createdAt',
        'batch.isUserMapped AS is_user_mapped',
        'batch.isNotified AS is_Notified',
        'batch.notifyAt AS notify_at',
        'campaign.id AS campaign_id',
        'campaign.campaign_name AS campaign_name',
      ])
      .addSelect('COUNT(slots.id)', 'slotCount')
      .addSelect(
        `MAX(
          CASE 
            WHEN batchVouchers.status = '${BatchVoucherStatus.ATTENDED}' 
            THEN 1 
            ELSE 0 
          END
        )`,
        'isAttended',
      )
      .groupBy('batch.id')
      .addGroupBy('campaign.id')
      .offset(skip)
      .limit(limit);

    // Count query (NO joins to slots → avoid inflated count)
    const countQuery = this.batchRepo
      .createQueryBuilder('batch')
      .leftJoin('batch.campaign', 'campaign');

    this.applyBatchFilters(countQuery, queryDto);

    const [rawData, total] = await Promise.all([
      dataQuery.getRawMany(),
      countQuery.getCount(),
    ]);

    // 🔹 Final mapping (clean response)
    const result = rawData.map((r) => ({
      id: r.batch_id,
      name: r.batch_name,
      stage: r.batch_stage,
      createdAt: r.batch_createdAt,
      startDate: r.batch_startDate,
      endDate: r.batch_endDate,
      campaignName: r.campaign_name,
      campaignId: r.campaign_id,
      slotDuration: r.batch_slotDuration,
      capacityPerSlot: r.capacity_per_slot,
      isUserMapped: r.is_user_mapped,
      isNotified: r.is_Notified,
      notifyAt: r.notify_at,
      slotCount: Number(r.slotCount),
      isAttended: Number(r.isAttended) === 1,
    }));

    return {
      statusCode: SUCCESS,
      message: 'Batches fetched successfully.',
      data: {
        result,
        total,
      },
    };
  } catch (e) {
    logger.error('Error occurred while fetching batches');
    return logsAndErrorHandling('BatchService - listBatches', e, {
      queryDto,
    });
  }
}

