  async verifyReceptionOtp(dto: VerifyReceptionOtpDto): Promise<any> {
    try {
      const { batchVoucherId, otp } = dto;
      await this.assertGreEligibleBatchVoucher(batchVoucherId);

      const key = receptionOtpKey(batchVoucherId);
      const cached = await this.cacheService.get<{
        otpHash: string;
        expireAt: string;
      }>(key);

      const now = Date.now();
      const expireAtTs = cached?.expireAt
        ? new Date(cached.expireAt).getTime()
        : 0;

      if (!cached?.otpHash || !expireAtTs || now >= expireAtTs) {
        throw new BadRequestException(
          'OTP expired. Please request a new OTP.',
        );
      }

      if (cached.otpHash !== this.hashOtp(otp)) {
        const attemptKey = receptionOtpAttemptsKey(batchVoucherId);
        const attempts =
          (await this.cacheService.get<number>(attemptKey)) ?? 0;
        const nextAttempts = attempts + 1;
        await this.cacheService.set(attemptKey, nextAttempts, {
          ttl: OTP_EXPIRY_TTL_MS,
        } as any);

        if (nextAttempts >= OTP_MAX_ATTEMPTS) {
          await this.cacheService.del(key);
          throw new BadRequestException(
            'Too many invalid OTP attempts. Please request a new OTP.',
          );
        }

        const remaining = OTP_MAX_ATTEMPTS - nextAttempts;
        throw new BadRequestException(
          `Invalid OTP. (${remaining} attempt${remaining === 1 ? '' : 's'} left)`,
        );
      }

      await this.cacheService.del(key);
      await this.cacheService.del(receptionOtpAttemptsKey(batchVoucherId));
      await this.cacheService.set(
        receptionOtpVerifiedKey(batchVoucherId),
        { verifiedAt: new Date().toISOString() },
        { ttl: RECEPTION_OTP_VERIFIED_TTL_MS } as any,
      );

      return {
        statusCode: SUCCESS,
        message: 'OTP verified successfully.',
        data: { batchVoucherId, verified: true },
      };
    } catch (e) {
      return logsAndErrorHandling('SlotService - verifyReceptionOtp', e, {
        dto,
      });
    }
  }

  async resendReceptionOtp(batchVoucherId: string, user?: any): Promise<any> {
    try {
      const mapping = await this.assertGreEligibleBatchVoucher(batchVoucherId);
      if (mapping.status === BatchVoucherStatus.ATTENDED) {
        throw new BadRequestException('Customer has already checked in.');
      }

      const key = receptionOtpKey(batchVoucherId);
      const existing = await this.cacheService.get<{
        otpHash: string;
        windowStart: string;
        resendCount: number;
        lastSentAt: string;
        expireAt: string;
      }>(key);

      const now = Date.now();
      if (existing?.lastSentAt) {
        const lastSentAt = new Date(existing.lastSentAt).getTime();
        if (now - lastSentAt < OTP_RESEND_TTL_MS) {
          throw new BadRequestException(
            'Please wait before requesting a new OTP.',
          );
        }

        const windowStart = new Date(existing.windowStart).getTime();
        const withinWindow = now - windowStart < OTP_EXPIRY_TTL_MS;
        const resendCount = withinWindow
          ? (existing.resendCount ?? 0) + 1
          : 1;

        if (withinWindow && resendCount > OTP_MAX_RESEND_COUNT) {
          throw new BadRequestException(
            'Too many OTP resend requests. Please try again later.',
          );
        }
      }

      const mobile = this.resolveRegisteredMobile(mapping);
      await this.issueReceptionOtp(mobile, batchVoucherId, existing);

      logger.info('Reception OTP resent', {
        batchVoucherId,
        greUserId: user?.dbId,
      });

      return {
        statusCode: SUCCESS,
        message: 'OTP resent successfully.',
        data: { batchVoucherId },
      };
    } catch (e) {
      return logsAndErrorHandling('SlotService - resendReceptionOtp', e, {
        batchVoucherId,
      });
    }
  }

  async markAttendance(
    dto: ReceptionCheckInDto,
    user: any,
  ): Promise<any> {
    try {
      const { batchVoucherId, headcount } = dto;

      const verified = await this.cacheService.get(
        receptionOtpVerifiedKey(batchVoucherId),
      );
      if (!verified) {
        throw new BadRequestException(
          'OTP verification is required before check-in.',
        );
      }

      const result = await this.dataSource.transaction(async (manager) => {
        const voucherRepo = manager.getRepository(EoiBatchVoucher);
        const mapping = await voucherRepo.findOne({
          where: { id: batchVoucherId },
          relations: ['slot'],
          lock: { mode: 'pessimistic_write' },
        });

        if (!mapping) {
          throw new NotFoundException('Customer record not found');
        }

        if (mapping.status === BatchVoucherStatus.ATTENDED) {
          throw new BadRequestException(
            'Attendance has already been recorded for this customer.',
          );
        }

        if (
          !mapping.slot ||
          !GRE_ELIGIBLE_SLOT_STATUSES.includes(mapping.slot.status) ||
          mapping.slot.deletedAt
        ) {
          throw new BadRequestException(
            'This record is not in an eligible slot for check-in.',
          );
        }

        mapping.status = BatchVoucherStatus.ATTENDED;
        mapping.headCount = headcount;
        mapping.checkedInAt = new Date();
        mapping.checkedInBy = user?.dbId ? String(user.dbId) : null;

        await voucherRepo.save(mapping);

        await this.cacheService.del(receptionOtpKey(batchVoucherId));
        await this.cacheService.del(receptionOtpVerifiedKey(batchVoucherId));
        await this.cacheService.del(receptionOtpAttemptsKey(batchVoucherId));

        return {
          batchVoucherId: mapping.id,
          attendanceStatus: mapping.status,
          headcount: mapping.headCount,
          checkedInAt: mapping.checkedInAt,
          checkedInBy: mapping.checkedInBy,
        };
      });

      logger.info('Reception check-in completed', {
        batchVoucherId,
        greUserId: user?.dbId,
      });

      return {
        statusCode: SUCCESS,
        message: 'Attendance marked successfully.',
        data: result,
      };
    } catch (e) {
      return logsAndErrorHandling('SlotService - markAttendance', e, { dto });
    }
  }

  private async issueReceptionOtp(
    mobile: string,
    batchVoucherId: string,
    existing?: {
      windowStart?: string;
      resendCount?: number;
      lastSentAt?: string;
    },
  ): Promise<void> {
    const otp = generateOtp();
    const now = new Date();
    const key = receptionOtpKey(batchVoucherId);

    await this.cacheService.set(
      key,
      {
        otpHash: this.hashOtp(otp),
        windowStart: existing?.windowStart ?? now.toISOString(),
        resendCount: existing?.resendCount ?? 1,
        lastSentAt: now.toISOString(),
        expireAt: new Date(now.getTime() + OTP_EXPIRY_TTL_MS).toISOString(),
      },
      { ttl: OTP_EXPIRY_TTL_MS } as any,
    );

    const cfg = getBrandCfg(this.config);
    const smsUrl =
      this.config.get<string>('SMS_URL') ??
      'https://sms.versatilesmshub.com/api/smsservices.php';
    const campaignId = this.config.get<string>('SMS_CAMPAIGN_ID') || 'otp';
    const channel = this.config.get<string>('SMS_CHANNEL') || 'otp';

    const message =
      `${otp} is the one-time password for reception check-in. ` +
      `OTP expires in 10 minutes. Please do not share it with anyone. ${cfg.signature}`;

    await this.sendReceptionSms({
      url: smsUrl,
      api: cfg.api,
      senderId: cfg.senderId,
      templateId: cfg.templateId,
      countryCode: cfg.country,
      number: mobile,
      message,
      campaignId,
      channel,
    });
  }

  private async sendReceptionSms(args: {
    url: string;
    api: string;
    senderId: string;
    templateId: string;
    countryCode: string;
    number: string;
    message: string;
    campaignId?: string;
    channel?: string;
  }): Promise<void> {
    try {
      const code = (args.countryCode || '91').replaceAll(/\D/g, '');
      const mobile = (args.number || '').replaceAll(/\D/g, '');
      const body = {
        api: args.api,
        senderid: args.senderId,
        campaignid: args.campaignId ?? 'otp',
        channel: args.channel ?? 'otp',
        templateid: args.templateId,
        dcs: '0',
        shorturl: 'NO',
        data: [
          {
            international: 'NO',
            countrycode: code,
            number: mobile,
            message: args.message,
            url: '',
          },
        ],
      };

      const { status, statusText } = await lastValueFrom(
        this.http.post(args.url, body, {
          headers: { 'Content-Type': 'application/json' },
          timeout: 8000,
        }),
      );
      if (status < 200 || status >= 300) {
        throw new Error(`SMS provider non-2xx: ${status} ${statusText}`);
      }
    } catch (e) {
      throw new InternalServerErrorException(
        `Failed to send OTP SMS: ${e?.message ?? e}`,
      );
    }
  }
}

      return logsAndErrorHandling('SlotService - exportSlotsExcel', e, {
        queryDto,
      });
    }
  }

  // --- Reception Desk (GRE) ---

  private buildGreVisibilityJoin(
    qb: SelectQueryBuilder<EoiBatchVoucher>,
    slotAlias = 'slot',
  ): SelectQueryBuilder<EoiBatchVoucher> {
    return qb
      .andWhere(`${slotAlias}.status IN (:...greEligibleStatuses)`, {
        greEligibleStatuses: GRE_ELIGIBLE_SLOT_STATUSES,
      })
      .andWhere(`${slotAlias}.deletedAt IS NULL`);
  }

  private async assertGreEligibleSlot(slotId: string): Promise<EoiBatchSlot> {
    const slot = await this.slotRepo.findOne({
      where: {
        id: slotId,
        status: In(GRE_ELIGIBLE_SLOT_STATUSES),
      },
    });

    if (!slot) {
      throw new BadRequestException(
        'Slot is not available for reception operations. Only Open or Active slots are allowed.',
      );
    }

    return slot;
  }

  private async assertGreEligibleBatchVoucher(
    batchVoucherId: string,
    relations: string[] = ['slot', 'voucher', 'batch'],
  ): Promise<EoiBatchVoucher> {
    const mapping = await this.batchVoucherRepo.findOne({
      where: { id: batchVoucherId },
      relations,
    });

    if (!mapping) {
      throw new NotFoundException('Customer record not found');
    }

    if (
      !mapping.slot ||
      !GRE_ELIGIBLE_SLOT_STATUSES.includes(mapping.slot.status) ||
      mapping.slot.deletedAt
    ) {
      throw new BadRequestException(
        'This record is not in an eligible slot for reception operations.',
      );
    }

    return mapping;
  }

  private resolveRegisteredMobile(batchVoucher: EoiBatchVoucher): string {
    if (batchVoucher.phone?.trim()) {
      return batchVoucher.phone.replace(/\D/g, '');
    }

    const mobile =
      batchVoucher.voucher?.applicant1?.personalDetails?.mobile ??
      batchVoucher.voucher?.applicant1?.personalDetails?.mobileNumber;

    if (mobile) {
      return String(mobile).replace(/\D/g, '');
    }

    throw new BadRequestException(
      'No registered mobile number found for this customer record.',
    );
  }

  private hashOtp(otp: string): string {
    return createHash('sha256').update(otp).digest('hex');
  }

  async listGreBatches(queryDto: ListGreBatchesDto): Promise<any> {
    try {
      const { page = 1, limit = 10, sortBy, search, campaignId, stage } =
        queryDto;
      const skip = (page - 1) * limit;

      const baseQuery = this.batchRepo
        .createQueryBuilder('batch')
        .innerJoin(
          'batch.slots',
          'slot',
          'slot.status IN (:...greEligibleStatuses) AND slot.deletedAt IS NULL',
          { greEligibleStatuses: GRE_ELIGIBLE_SLOT_STATUSES },
        )
        .leftJoin('batch.campaign', 'campaign')
        .where('batch.status = :batchStatus', {
          batchStatus: BatchStatus.ACTIVE,
        })
        .andWhere('batch.deletedAt IS NULL');

      if (campaignId) {
        baseQuery.andWhere('batch.campaignId = :campaignId', { campaignId });
      }
      if (stage) {
        baseQuery.andWhere('batch.stage = :stage', { stage });
      }
      if (search) {
        baseQuery.andWhere(
          '(LOWER(batch.name) LIKE LOWER(:search) OR LOWER(campaign.campaignName) LIKE LOWER(:search))',
          { search: `%${search}%` },
        );
      }

      if (sortBy) {
        const [field, direction] = sortBy.split(':');
        baseQuery.orderBy(
          `batch.${field}`,
          (direction || 'DESC').toUpperCase() as 'ASC' | 'DESC',
        );
      } else {
        baseQuery.orderBy('batch.createdAt', 'DESC');
      }

      const dataQuery = baseQuery
        .clone()
        .select([
          'batch.id AS batch_id',
          'batch.name AS batch_name',
          'batch.stage AS batch_stage',
          'batch.startDate AS batch_startDate',
          'batch.endDate AS batch_endDate',
          'campaign.id AS campaign_id',
          'campaign.campaign_name AS campaign_name',
        ])
        .addSelect('COUNT(DISTINCT slot.id)', 'eligibleSlotCount')
        .groupBy('batch.id')
        .addGroupBy('campaign.id')
        .offset(skip)
        .limit(limit);

      const countQuery = baseQuery.clone().select('batch.id').distinct(true);

      const [rawData, total] = await Promise.all([
        dataQuery.getRawMany(),
        countQuery.getCount(),
      ]);

      const result = rawData.map((r) => ({
        id: r.batch_id,
        name: r.batch_name,
        stage: r.batch_stage,
        startDate: r.batch_startDate,
        endDate: r.batch_endDate,
        campaignId: r.campaign_id,
        campaignName: r.campaign_name,
        eligibleSlotCount: Number(r.eligibleSlotCount),
      }));

      return {
        statusCode: SUCCESS,
        message: 'Reception batches fetched successfully.',
        data: { result, total, page, limit },
      };
    } catch (e) {
      return logsAndErrorHandling('SlotService - listGreBatches', e, {
        queryDto,
      });
    }
  }

  async listGreSlots(queryDto: ListGreSlotsDto): Promise<any> {
    try {
      const { page = 1, limit = 10, batchId, sortBy, search } = queryDto;
      const offset = (page - 1) * limit;

      const batch = await this.batchRepo.findOne({
        where: { id: batchId, status: BatchStatus.ACTIVE },
        relations: ['campaign'],
        select: {
          id: true,
          name: true,
          isUserMapped: true,
          campaign: { campaignName: true },
        },
      });

      if (!batch) {
        throw new NotFoundException('Batch not found or not active');
      }

      const allowedSortFields: Record<string, string> = {
        createdAt: 'slot.createdAt',
        startTime: 'slot.startTime',
        endTime: 'slot.endTime',
        sequence: 'slot.sequence',
        date: 'slot.date',
      };

      let orderByField = 'slot.sequence';
      let orderDirection: 'ASC' | 'DESC' = 'ASC';

      if (sortBy) {
        const [field, direction] = sortBy.split(':');
        if (allowedSortFields[field]) {
          orderByField = allowedSortFields[field];
        }
        if (direction && ['ASC', 'DESC'].includes(direction.toUpperCase())) {
          orderDirection = direction.toUpperCase() as 'ASC' | 'DESC';
        }
      }

      const query = this.slotRepo
        .createQueryBuilder('slot')
        .select([
          'slot.id',
          'slot.name',
          'slot.batchId',
          'slot.capacity',
          'slot.sequence',
          'slot.startTime',
          'slot.endTime',
          'slot.date',
          'slot.status',
          'slot.filledCount',
          'slot.createdAt',
        ])
        .where('slot.batchId = :batchId', { batchId })
        .andWhere('slot.status IN (:...greEligibleStatuses)', {
          greEligibleStatuses: GRE_ELIGIBLE_SLOT_STATUSES,
        })
        .andWhere('slot.deletedAt IS NULL');

      if (search) {
        query.andWhere('slot.name LIKE :search', { search: `%${search}%` });
      }

      query.orderBy(orderByField, orderDirection).offset(offset).limit(limit);

      const [slots, total] = await query.getManyAndCount();

      const attendedCounts = await Promise.all(
        slots.map((slot) =>
          this.batchVoucherRepo.count({
            where: {
              slotId: slot.id,
              status: BatchVoucherStatus.ATTENDED,
            },
          }),
        ),
      );

      const result = slots.map((slot, index) => ({
        id: slot.id,
        name: slot.name,
        batchId: slot.batchId,
        capacity: slot.capacity,
        sequence: slot.sequence,
        startTime: slot.startTime,
        endTime: slot.endTime,
        date: slot.date,
        status: slot.status,
        filledCount: slot.filledCount,
        attended: attendedCounts[index],
      }));

      return {
        statusCode: SUCCESS,
        message: 'Reception slots fetched successfully.',
        data: {
          result,
          campaignName: batch.campaign?.campaignName,
          batchName: batch.name,
          isUserMapped: batch.isUserMapped,
          total,
          page,
          limit,
        },
      };
    } catch (e) {
      return logsAndErrorHandling('SlotService - listGreSlots', e, {
        queryDto,
      });
    }
  }

  private createViewRecordsQuery(
    batchId: string,
    slotId?: string,
    search?: string,
  ): SelectQueryBuilder<EoiBatchVoucher> {
    const qb = this.batchVoucherRepo
      .createQueryBuilder('bv')
      .innerJoin('bv.slot', 'slot')
      .innerJoin('bv.batch', 'batch')
      .innerJoin('bv.voucher', 'voucher')
      .leftJoin('voucher.closingRm', 'closingRm')
      .leftJoin('voucher.createdBy', 'createdBy')
      .where('bv.batchId = :batchId', { batchId })
      .andWhere('voucher.isDeleted = :isDeleted', { isDeleted: false });

    this.buildGreVisibilityJoin(qb);

    if (slotId) {
      qb.andWhere('bv.slotId = :slotId', { slotId });
    }

    if (search?.trim()) {
      const term = `%${search.trim()}%`;
      qb.andWhere(
        `(voucher.uniqueReferenceId LIKE :term
          OR voucher.voucherId LIKE :term
          OR voucher.stdEoiId LIKE :term
          OR voucher.preEoiId LIKE :term
          OR bv.customerName LIKE :term
          OR bv.phone LIKE :term
          OR batch.name LIKE :term)`,
        { term },
      );
    }

    return qb;
  }

  private mapViewRecordRow(row: EoiBatchVoucher) {
    return {
      id: row.id,
      paymentReferenceId: row.voucher?.uniqueReferenceId ?? null,
      voucherId: row.voucher?.voucherId ?? null,
      standardEoiId: row.voucher?.stdEoiId ?? null,
      preferentialEoiId: row.voucher?.preEoiId ?? null,
      customerName: row.customerName ?? null,
      mobileNumber: row.phone ?? null,
      batchNo: row.batch?.name ?? null,
      batchId: row.batchId,
      slotId: row.slotId,
      slotName: row.slot?.name ?? null,
      date: row.slot?.date ?? null,
      startTime: row.slot?.startTime ?? null,
      attendanceStatus: row.status,
      headcount: row.headCount ?? null,
      closingRm: row.voucher?.closingRm?.name ?? null,
      sourcingRm: row.voucher?.createdBy?.name ?? null,
      checkedInAt: row.checkedInAt ?? null,
    };
  }

  async listViewRecords(queryDto: ListViewRecordsDto): Promise<any> {
    try {
      const { page = 1, limit = 10, batchId, slotId, sortBy, search } =
        queryDto;
      const offset = (page - 1) * limit;

      const qb = this.createViewRecordsQuery(batchId, slotId, search);

      if (sortBy) {
        const [field, direction] = sortBy.split(':');
        const sortMap: Record<string, string> = {
          customerName: 'bv.customerName',
          assignedAt: 'bv.assignedAt',
          checkedInAt: 'bv.checkedInAt',
          date: 'slot.date',
          startTime: 'slot.startTime',
        };
        if (sortMap[field]) {
          qb.orderBy(
            sortMap[field],
            (direction || 'DESC').toUpperCase() as 'ASC' | 'DESC',
          );
        }
      } else {
        qb.orderBy('bv.assignedAt', 'DESC');
      }

      qb.skip(offset).take(limit);

      const [rows, total] = await qb
        .select([
          'bv.id',
          'bv.batchId',
          'bv.slotId',
          'bv.customerName',
          'bv.phone',
          'bv.status',
          'bv.headCount',
          'bv.checkedInAt',
          'bv.assignedAt',
          'slot.id',
          'slot.name',
          'slot.date',
          'slot.startTime',
          'batch.id',
          'batch.name',
          'voucher.id',
          'voucher.uniqueReferenceId',
          'voucher.voucherId',
          'voucher.stdEoiId',
          'voucher.preEoiId',
          'closingRm.id',
          'closingRm.name',
          'createdBy.id',
          'createdBy.name',
        ])
        .getManyAndCount();

      return {
        statusCode: SUCCESS,
        message: 'View records fetched successfully.',
        data: {
          result: rows.map((row) => this.mapViewRecordRow(row)),
          total,
          page,
          limit,
        },
      };
    } catch (e) {
      return logsAndErrorHandling('SlotService - listViewRecords', e, {
        queryDto,
      });
    }
  }

  async universalSearch(queryDto: UniversalSearchDto): Promise<any> {
    if (!queryDto.search?.trim()) {
      throw new BadRequestException('Search term is required');
    }
    return this.listViewRecords(queryDto);
