  )
  @Delete('delete/:slotId')
  async deleteBatch(
    @User() user: any,
    @Param('slotId') slotId: string,
  ): Promise<any> {
    return await this.slotService.deleteSlot(user, slotId);
  }

  @UseGuards(RmAdminAuthGuard, RolesGuard)
  @Roles(RolesEnum.ADMIN, RolesEnum.SUPER_ADMIN)
